#include <bits/stdc++.h>
using namespace std;

const int N=1003;

struct Node{
    int fa,cnt,sum;
    //fa存父亲，cnt存节点数，sum存权值和
}p[N];

int n,root,ans;

int Find(){
    int tmp=0;
    for(int i=1;i<=n;i++)
        if(p[i].fa && (!tmp || p[i].sum*p[tmp].cnt>p[tmp].sum*p[i].cnt))
            tmp=i;
    return tmp;
}

int main(){
    scanf("%d%d",&n,&root);
    for(int i=1;i<=n;i++){
        scanf("%d",&p[i].sum);
        p[i].cnt=1,ans+=p[i].sum;
    }
    for(int i=1;i<n;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        p[v].fa=u;
    }
    for(int i=1;i<n;i++){
        int t=Find();
        for(int j=1;j<=n;j++)
            if(p[j].fa==t)
                p[j].fa=p[t].fa;
        int fa=p[t].fa;
        p[t].fa=0;
        ans+=p[fa].cnt*p[t].sum;
        p[fa].cnt+=p[t].cnt,p[fa].sum+=p[t].sum;
    }
    printf("%d",ans);
    return 0;
}
